import re
import json

# 1. Obtener el HTML del input (tipo texto)
try:
    html_content = _input.first().json.data
except Exception as e:
    # Si la data no está en .json.data, intentar con .json
    html_content = _input.first().json
    if not isinstance(html_content, str):
        raise Exception(f"No se pudo leer el HTML como string. Error: {e}")

extracted_list = []
error_messages = []

try:
    # 2. EXTRAER EL ARRAY 'es'
    match_es = re.search(r'es:\s*(\[[\s\S]*?\])\s*,', html_content)

    if match_es:
        es_string = match_es.group(1)

        # 3. Limpiar la coma sobrante (trailing comma)
        es_string_cleaned = re.sub(r',\s*(?=\])', '', es_string)

        try:
            # 4. Convertir el string a una lista de Python
            extracted_list = json.loads(es_string_cleaned)
        except json.JSONDecodeError as e:
            error_messages.append(f"Error al decodificar JSON de 'es': {e}")
    else:
        error_messages.append("No se pudo encontrar el array 'es'.")

    # 5. DEVOLVER EL RESULTADO PARA N8N
    if extracted_list:
        # --- ESTA ES LA CORRECCIÓN ---
        # En lugar de: { "json": [...] }
        # Devolvemos:   { "json": { "feriados_es": [...] } }
        # Ahora "json" sí es un diccionario.
        return [
            {
                "json": {
                    "feriados_es": extracted_list
                }
            }
        ]
    else:
        raise Exception(f"No se pudo extraer la lista 'es'. Errores: {', '.join(error_messages)}")

except Exception as e:
    raise Exception(f"Ocurrió un error inesperado: {e}")

