// NODO DE FILTRADO FINAL
// Se ejecuta una sola vez al terminar el bucle

const items = $input.all(); // Recibe todos los resultados de los scrappers
const targetMonth = $('Configurar Paises y Fechas').first().json.targetMonth;
const targetYear = $('Configurar Paises y Fechas').first().json.targetYear;

let feriadosDelMes = [];

for (const item of items) {
  const pais = item.json.pais;
  const todosLosFeriados = item.json.feriados_raw || [];

  for (const f of todosLosFeriados) {
    // Asumimos formato YYYY-MM-DD
    const fechaParts = f.fecha.split('-');
    const mes = parseInt(fechaParts[1]);
    const anio = parseInt(fechaParts[0]);

    if (mes === targetMonth && anio === targetYear) {
      feriadosDelMes.push({
        pais: pais,
        fecha: f.fecha,
        motivo: f.motivo
      });
    }
  }
}

return feriadosDelMes;

const feriados = $input.all().map(i => i.json);
