html += `<tr style="background-color: #f2f2f2;"><th style="border: 1px solid #ddd; padding: 8px;">País</th><th style="border: 1px solid #ddd; padding: 8px;">Fecha</th><th style="border: 1px solid #ddd; padding: 8px;">Motivo</th></tr>`;

